var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배…….","JPN":"レイ先輩……","ENG":"Ray...","TWN":"雷伊前輩……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아직 그 이름으로 불러 주는군요. 유미나님.","JPN":"まだその名前で呼んでくれるんですね。ヤナギ・ミナ様。","ENG":"You still call me by that name, Yoo Mina.","TWN":"你還這樣稱呼我呢，劉米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"센트럴 팰리스에서 만났을 때 충고드렸죠. 준비는 모두 마치셨나요?","JPN":"セントラルパレスで会った時、忠告しましたよね。準備はできていますか？","ENG":"I warned you when we met back at the Central Palace. Are you ready now?","TWN":"在聖特羅貝里斯見面時我就給過幾位忠告了。你們都準備好了吧？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……방금 우리가 봤던 것 모두, 정말이야?","JPN":"……今私たちが見たのは全部、本当なの？","ENG":"...Is it true? What we all just saw.","TWN":"……剛才我們看到的，都是真的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 과장도 누락도 없는 순수한 진실입니다.","JPN":"はい、誇張も欠落もない、紛れもない事実です。","ENG":"Yes. It is the truth, without any exaggerations or omissions.","TWN":"是的，沒有誇飾，沒有遺漏，這就是完完本本的真相。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이 세계…….","JPN":"この世界……","ENG":"This world...","TWN":"這個世界……"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아홉 대륙을 품고 있던 세계가 클리파의 역할을 하기 시작한 날부터.","JPN":"九つの大陸を持つ世界がクリファの役割をし始めた日から。","ENG":"Since the day this world of nine continents became Qlipha.","TWN":"這片曾經有九塊大陸的世界，直至變成逆卡巴拉為止……"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"오늘에 이르기까지, 여러분이 겪은 기억은 조금도 변형되지 않았어요.","JPN":"今日に至るまで、皆さんの経験した記憶は少しも変えられていません。","ENG":"Up to this very day, what you have experienced has not been modified in any way.","TWN":"也就是說到今天為止，幾位所經歷的這個記憶也沒有任何修飾。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그 날, 저는 잘못된 선택을 내렸을지도 모릅니다.","JPN":"あの日、僕は間違った選択をしてしまったのかもしれません。","ENG":"Perhaps I made the wrong choice that day.","TWN":"或許，那天我做了錯誤的選擇。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그리고 제가 선택해 짊어졌던 대가를, 다른 이에게 넘겨 주길 원치도 않아요.","JPN":"そして自分の選択による代償を、他の者に負わせたくもありません。","ENG":"But then, I didn't want to force anyone to take over this burden. It was the price I had to pay.","TWN":"不過，我也不想把我選擇的代價留給別人來承擔。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"유미나님의 세계에 선택 받은 대적자 분도 동의하셨습니다.","JPN":"ミナ様の世界の選ばれし敵対者も、同意しています。","ENG":"The Antagonist who was chosen by your world agreed as well, Yoo Mina.","TWN":"被你們世界選中的敵對者也同意了，劉米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만……","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런 짓을 하면 기억 속에 나왔던 마왕과 다를 바 없는 거 아냐?","JPN":"そんなことをしたら、記憶の中の魔王と変わらないでしょ？","ENG":"That only makes you the same as the Demon Lord from your memories.","TWN":"做下那種事的話，不就跟你記憶中的魔王沒什麼兩樣了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇게까지 막으려고 애썼으면서, 왜 똑같은 짓을 저지르려고 하는 거야?","JPN":"あれほど止めようとしていたのに、何で自分で同じことをやろうとしているの？","ENG":"If you tried so hard to stop him, why are you following in his footsteps now?","TWN":"你曾經那麼努力地阻止魔王，為什麼要做出同樣的事呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 제 손에 죽길 택했던 그 분의 심정도 이해합니다.","JPN":"はい、僕の手によって倒れることを選んだあの者の気持ちも理解できます。","ENG":"Yes. I understand how he must have felt, wanting to die in my hands.","TWN":"是的，我也能理解他選擇死在我手裡的心情了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"멈추지 못하고, 다른 누군가의 파멸이 되어야 한다는 사실이 더 이상 견딜 수 없었던 거겠죠.","JPN":"止まることもできず、他の誰かを破滅させなければいけないことに、もう我慢ができなかったんでしょう。","ENG":"He couldn't bear the fact that he has to be the one who destroys others, without being able to stop.","TWN":"應該是再也無法承受不能停止，只能成為其他人的毀滅這件事了吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저 역시도…… 그렇습니다.","JPN":"それは……僕も同じです。","ENG":"I... feel the same.","TWN":"我也……如此。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};